const { Manifold, label } = api;

// Helper: axis-aligned box from min..max
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Helper: hull of two boxes (creates a wedge/tapered shape)
function taperBox(x0, x1, y0, y1, z0, z1, tx0, tx1, ty0, ty1) {
  const pts = [
    [x0, y0, z0],
    [x1, y0, z0],
    [x0, y1, z0],
    [x1, y1, z0],
    [tx0, ty0, z1],
    [tx1, ty0, z1],
    [tx0, ty1, z1],
    [tx1, ty1, z1],
  ];
  const spheres = pts.map(p => Manifold.sphere(0.01, 4).translate(p));
  return Manifold.hull(spheres);
}

// Body: main torso box, sitting pose
const body = label(box([-5, -8, 4], [5, 4, 11]), 'body');

// Chest/belly white patch (front lower area, overlapping body)
const chest = label(box([-3.5, -8.1, 4], [3.5, -4, 9]), 'chest');

// Head: slightly wider cube, sitting on top of body
const head = label(box([-4.5, -7, 10.5], [4.5, 2, 16.5]), 'head');

// Snout: rectangular wedge pointing forward (-Y direction)
const snout = label(box([-2.5, -9.5, 11], [2.5, -6.5, 14]), 'snout');

// Snout tip (white): front face of snout
const snoutTip = label(box([-2, -9.8, 11.5], [2, -9, 13.5]), 'snoutTip');

// Nose: dark nub on snout top-front
const nose = label(box([-1, -9.9, 13.2], [1, -9.2, 14.2]), 'nose');

// Ears: triangular prisms (hull of points)
// Left ear (-X side)
const leftEarPts = [
  [-4.5, -5, 16.5],
  [-4.5, -1, 16.5],
  [-4.5, -5, 16.5],
  [-2, -3, 20],
  [-6.5, -5, 16.5],
  [-6.5, -1, 16.5],
  [-4, -3, 20],
];
const leftEarSpheres = leftEarPts.map(p => Manifold.sphere(0.01, 4).translate(p));
const leftEar = label(Manifold.hull(leftEarSpheres), 'earLeft');

// Right ear (+X side)
const rightEarPts = [
  [4.5, -5, 16.5],
  [4.5, -1, 16.5],
  [2, -3, 20],
  [6.5, -5, 16.5],
  [6.5, -1, 16.5],
  [4, -3, 20],
];
const rightEarSpheres = rightEarPts.map(p => Manifold.sphere(0.01, 4).translate(p));
const rightEar = label(Manifold.hull(rightEarSpheres), 'earRight');

// Ear tips (dark inner): slightly inset wedge inside each ear
const leftEarTipPts = [
  [-4.5, -4, 16.5],
  [-4.5, -2, 16.5],
  [-6.5, -4, 16.5],
  [-6.5, -2, 16.5],
  [-4.5, -3, 19],
  [-5.5, -3, 19],
];
const leftEarTipSpheres = leftEarTipPts.map(p => Manifold.sphere(0.01, 4).translate(p));
const leftEarTip = label(Manifold.hull(leftEarTipSpheres), 'earTipLeft');

const rightEarTipPts = [
  [4.5, -4, 16.5],
  [4.5, -2, 16.5],
  [6.5, -4, 16.5],
  [6.5, -2, 16.5],
  [4.5, -3, 19],
  [5.5, -3, 19],
];
const rightEarTipSpheres = rightEarTipPts.map(p => Manifold.sphere(0.01, 4).translate(p));
const rightEarTip = label(Manifold.hull(rightEarTipSpheres), 'earTipRight');

// Legs: 4 short cylinders
const legFL = label(box([-4.5, -7.5, 0], [-2, -5, 4.5]), 'legFront');
const legFR = label(box([2, -7.5, 0], [4.5, -5, 4.5]), 'legFront');
const legBL = label(box([-4.5, 1, 0], [-2, 3.5, 4.5]), 'legBack');
const legBR = label(box([2, 1, 0], [4.5, 3.5, 4.5]), 'legBack');

// Leg socks (dark lower portion)
const sockFL = label(box([-4.5, -7.5, 0], [-2, -5, 2]), 'sock');
const sockFR = label(box([2, -7.5, 0], [4.5, -5, 2]), 'sock');
const sockBL = label(box([-4.5, 1, 0], [-2, 3.5, 2]), 'sock');
const sockBR = label(box([2, 1, 0], [4.5, 3.5, 2]), 'sock');

// Tail: large bushy tapered shape sweeping up and behind (+Y side)
// Base at body rear, sweeping up
const tailBasePts = [
  [-4, 4, 5],
  [-4, 4, 9],
  [4, 4, 5],
  [4, 4, 9],
  [-2.5, 10, 6],
  [-2.5, 10, 10],
  [2.5, 10, 6],
  [2.5, 10, 10],
];
const tailBaseSpheres = tailBasePts.map(p => Manifold.sphere(0.01, 4).translate(p));
const tailBase = Manifold.hull(tailBaseSpheres);

// Tail upper portion tapering
const tailTopPts = [
  [-2, 8, 9],
  [2, 8, 9],
  [-2, 10, 9],
  [2, 10, 9],
  [-1, 8, 15],
  [1, 8, 15],
  [-1, 10, 15],
  [1, 10, 15],
];
const tailTopSpheres = tailTopPts.map(p => Manifold.sphere(0.01, 4).translate(p));
const tailTop = Manifold.hull(tailTopSpheres);

const tailShape = label(tailBase.add(tailTop), 'tail');

// Tail tip (white)
const tailTipPts = [
  [-1, 8, 13],
  [1, 8, 13],
  [-1, 10, 13],
  [1, 10, 13],
  [0, 9, 15.5],
];
const tailTipSpheres = tailTipPts.map(p => Manifold.sphere(0.01, 4).translate(p));
const tailTip = label(Manifold.hull(tailTipSpheres), 'tailTip');

// Assemble everything - all parts overlap body by 0.5+ units
return body
  .add(chest)
  .add(head)
  .add(snout)
  .add(snoutTip)
  .add(nose)
  .add(leftEar)
  .add(rightEar)
  .add(leftEarTip)
  .add(rightEarTip)
  .add(legFL).add(legFR).add(legBL).add(legBR)
  .add(sockFL).add(sockFR).add(sockBL).add(sockBR)
  .add(tailShape)
  .add(tailTip);
